def validate_uploaded_image(data: bytes, source_name: str | None) -> dict[str, object]:
    if not data:
        raise ConversionError("No file uploaded.", status_code=400)
    try:
        return validate_image(data, source_name)
    except ValueError as error:
        raise ConversionError(str(error), status_code=400) from error
    except Exception as error:
        raise ConversionError("Validation failed unexpectedly.", status_code=500) from error

