def compare_image_pair(
    left_data: bytes,
    left_name: str | None,
    right_data: bytes,
    right_name: str | None,
) -> dict[str, object]:
    if not left_data or not right_data:
        raise ConversionError("Both images are required.", status_code=400)
    try:
        return compare_images(left_data, left_name, right_data, right_name)
    except ValueError as error:
        raise ConversionError(str(error), status_code=400) from error
    except Exception as error:
        raise ConversionError("Image comparison failed unexpectedly.", status_code=500) from error

