def refine_image(
    data: bytes,
    format_name: str | None,
    post_filter: str,
    max_mb: float | int | str | None = None,
    strip_metadata: bool = True,
) -> tuple[bytes, OutputFormat]:
    output_format = parse_output_format(format_name)
    if output_format is None:
        raise ConversionError("Invalid output format.", status_code=400)
    if not data:
        raise ConversionError("No file uploaded.", status_code=400)

    try:
        output = refine_compressed_image(
            data,
            output_format,
            post_filter,
            max_mb=max_mb,
            strip_metadata=strip_metadata,
        )
    except ConversionError:
        raise
    except ValueError as error:
        raise ConversionError(str(error), status_code=400) from error
    except Exception as error:
        raise ConversionError("Finish filter failed unexpectedly.", status_code=500) from error

    return output, output_format
